<script>
    jQuery(document).ready(function($) {

        // Get all necessary elements
        const filterButtons = $('.connect-drive-button[data-filter]');
        const searchInput = $('#feature-search');
        const featureItems = $('.connect-drive-feature__content');
        const container = $('#feature-items-container');

        // State variables
        let currentFilter = 'all';
        let currentSearch = '';

        // Main filter function
        function filterItems() {
            let visibleCount = 0;

            featureItems.each(function(index) {
                const item = $(this);

                // Get item data
                const category = item.data('category');

                // Get searchable text from data attributes
                let searchTitle = item.data('search-title') || '';
                let searchDescription = item.data('search-description') || '';

                // Get display text as fallback
                if (!searchTitle) {
                    const titleElement = item.find('.feature-sub-title');
                    searchTitle = titleElement.length ? titleElement.text().toLowerCase() : '';
                }

                if (!searchDescription) {
                    const descElement = item.find('.feature-sub-description');
                    searchDescription = descElement.length ? descElement.text().toLowerCase() : '';
                }

                // Check category filter
                const matchesCategory = currentFilter === 'all' || category === currentFilter;

                // Check search filter
                let matchesSearch = true;
                if (currentSearch !== '') {
                    matchesSearch = searchTitle.includes(currentSearch) ||
                        searchDescription.includes(currentSearch);
                }

                // Show or hide based on both filters
                if (matchesCategory && matchesSearch) {
                    item.show();
                    visibleCount++;

                    // Add animation class
                    item.addClass('filter-animate');
                    setTimeout(() => {
                        item.removeClass('filter-animate');
                    }, 300);
                } else {
                    item.hide();
                }
            });

            // Update active button state
            filterButtons.each(function() {
                const btn = $(this);
                const filterValue = btn.data('filter');
                if (filterValue === currentFilter) {
                    btn.addClass('active');
                } else {
                    btn.removeClass('active');
                }
            });

            // Show/hide no results message
            showNoResultsMessage(visibleCount === 0);
        }

        // Function to show no results message
        function showNoResultsMessage(show) {
            let noResultsMsg = $('.no-results-message');

            if (show) {
                if (noResultsMsg.length === 0) {
                    noResultsMsg = $('<div>', {
                        class: 'no-results-message',
                        text: 'No features found matching your criteria.'
                    });
                    container.append(noResultsMsg);
                }
            } else {
                noResultsMsg.remove();
            }
        }

        // Button click handlers
        if (filterButtons.length > 0) {
            filterButtons.on('click', function(e) {
                e.preventDefault();
                currentFilter = $(this).data('filter');
                console.log('Filter button clicked:', currentFilter);
                filterItems();
            });
        }

        // Search input handler
        if (searchInput.length > 0) {
            // Input event for real-time search
            searchInput.on('input', function() {
                currentSearch = $(this).val().trim().toLowerCase();
                filterItems();
            });

            // Search on Enter key
            searchInput.on('keypress', function(e) {
                if (e.key === 'Enter') {
                    e.preventDefault();
                    currentSearch = $(this).val().trim().toLowerCase();
                    filterItems();
                }
            });

            // Add clear button functionality
            const searchContainer = $('.connect-drive-feature__search');

            if (searchContainer.length > 0) {
                // Create clear button
                const clearButton = $('<span>', {
                    html: '×',
                    class: 'search-clear',
                    css: {
                        position: 'absolute',
                        right: '20px',
                        top: '50%',
                        transform: 'translateY(-50%)',
                        cursor: 'pointer',
                        fontSize: '24px',
                        color: '#5C637E',
                        display: 'none',
                        zIndex: '10',
                        fontWeight: 'bold',
                        background: 'white',
                        width: '24px',
                        height: '24px',
                        borderRadius: '50%',
                        textAlign: 'center',
                        lineHeight: '22px'
                    }
                });

                searchContainer.css('position', 'relative');
                searchContainer.append(clearButton);

                // Show/hide clear button based on input
                searchInput.on('input', function() {
                    clearButton.css('display', $(this).val() ? 'block' : 'none');
                });

                // Clear search on button click
                clearButton.on('click', function() {
                    searchInput.val('');
                    clearButton.css('display', 'none');
                    currentSearch = '';
                    filterItems();
                    searchInput.focus();
                });
            }
        } else {
           'Search input not found!';
        }

        // Initialize with all items visible
        filterItems();
    });
</script>